-- Curriculum seed: makes the A1 -> C2 learning path reachable on a fresh install.
-- Adds lesson ordering, then seeds the curriculum spine (lessons), core vocabulary,
-- grammar rules, conversation templates and pronunciation exercises.
-- Lesson sections/exercises are intentionally NOT seeded: the app generates and
-- persists them with AI the first time a lesson is opened.
--
-- Topic conventions (coupled to src/lib/curriculum.ts):
--   'exam'        -> the lesson is a level checkpoint (learning-path gating) and
--                    surfaces as an exam module in /api/exam/modules
--   'tcf' / 'tef' -> exam flavor used to classify exam modules

-- 1. Lesson ordering ---------------------------------------------------------

ALTER TABLE public.lessons ADD COLUMN IF NOT EXISTS order_index INTEGER DEFAULT 0;
CREATE INDEX IF NOT EXISTS idx_lessons_level_order ON public.lessons(level, order_index);

-- 2. Lessons (curriculum spine, 12 per level) --------------------------------

