-- 4. Grammar rules -----------------------------------------------------------

INSERT INTO public.grammar_rules (title, description, examples, level, category) VALUES
($$Definite and indefinite articles$$, $$French nouns are masculine or feminine. Use le/la/les for specific nouns and un/une/des for unspecific ones. Le and la become l' before a vowel.$$, ARRAY[$$le livre → the book$$, $$la table → the table$$, $$l'ami → the friend$$, $$une idée → an idea$$], 'A1', 'articles'),
($$Present tense of être and avoir$$, $$Être (to be) and avoir (to have) are irregular and must be memorized; they also serve as auxiliaries for compound tenses.$$, ARRAY[$$je suis, tu es, il est, nous sommes, vous êtes, ils sont$$, $$j'ai, tu as, il a, nous avons, vous avez, ils ont$$], 'A1', 'conjugation'),
($$Regular -er verbs$$, $$Remove -er and add -e, -es, -e, -ons, -ez, -ent. About 90% of French verbs follow this pattern.$$, ARRAY[$$parler : je parle, nous parlons$$, $$aimer : tu aimes, ils aiment$$], 'A1', 'conjugation'),
($$Negation with ne... pas$$, $$Wrap the conjugated verb with ne and pas. Ne becomes n' before a vowel.$$, ARRAY[$$Je ne parle pas anglais.$$, $$Elle n'aime pas le café.$$], 'A1', 'negation'),
($$Question formation$$, $$Ask questions with intonation, est-ce que, or inversion. Question words: qui, que, où, quand, pourquoi, comment.$$, ARRAY[$$Tu viens ? / Est-ce que tu viens ? / Viens-tu ?$$, $$Où habites-tu ?$$], 'A1', 'questions'),
($$Possessive adjectives$$, $$Mon/ma/mes, ton/ta/tes, son/sa/ses agree with the noun possessed, not the possessor.$$, ARRAY[$$mon frère, ma sœur, mes parents$$, $$sa voiture (his OR her car)$$], 'A1', 'adjectives'),
($$Passé composé with avoir$$, $$Most verbs form the past with avoir + past participle. Participles: -er → -é, -ir → -i, -re → -u.$$, ARRAY[$$J'ai mangé une pomme.$$, $$Nous avons fini le travail.$$, $$Elle a vendu sa maison.$$], 'A2', 'past-tenses'),
($$Passé composé with être$$, $$Movement/state-change verbs (aller, venir, partir...) and all reflexives use être; the participle agrees with the subject.$$, ARRAY[$$Elle est allée à Paris.$$, $$Ils sont partis tôt.$$, $$Nous nous sommes levés à huit heures.$$], 'A2', 'past-tenses'),
($$L'imparfait$$, $$Describes past habits, descriptions and ongoing actions. Stem = nous-form minus -ons, plus -ais, -ais, -ait, -ions, -iez, -aient.$$, ARRAY[$$Quand j'étais petit, je jouais au foot.$$, $$Il faisait beau ce jour-là.$$], 'A2', 'past-tenses'),
($$Futur proche and futur simple$$, $$Futur proche = aller + infinitive (immediate plans). Futur simple = infinitive + -ai, -as, -a, -ons, -ez, -ont (predictions, promises).$$, ARRAY[$$Je vais partir demain.$$, $$Nous voyagerons en été.$$], 'A2', 'future'),
($$Direct and indirect object pronouns$$, $$COD: me, te, le, la, nous, vous, les. COI: me, te, lui, nous, vous, leur. They precede the conjugated verb.$$, ARRAY[$$Je le vois. (I see him)$$, $$Je lui parle. (I speak to him/her)$$], 'A2', 'pronouns'),
($$Comparatives and superlatives$$, $$plus/moins/aussi + adjective + que; superlative adds le/la/les. Bon → meilleur; bien → mieux.$$, ARRAY[$$Paul est plus grand que Marie.$$, $$C'est le meilleur restaurant de la ville.$$], 'A2', 'comparison'),
($$Le subjonctif présent$$, $$Used after expressions of necessity, will, emotion and doubt (il faut que, je veux que, bien que). Stem from ils-form + -e, -es, -e, -ions, -iez, -ent.$$, ARRAY[$$Il faut que tu fasses tes devoirs.$$, $$Je suis content que vous soyez là.$$], 'B1', 'subjunctive'),
($$Relative pronouns qui, que, dont, où$$, $$Qui = subject, que = object, dont = of which/whose, où = where/when.$$, ARRAY[$$L'homme qui parle est mon voisin.$$, $$Le livre que je lis est passionnant.$$, $$Le film dont tu parles est sorti hier.$$], 'B1', 'pronouns'),
($$The conditional$$, $$Future stem + imparfait endings. Expresses politeness, wishes and hypotheses.$$, ARRAY[$$Je voudrais un café.$$, $$Si j'avais le temps, je voyagerais.$$], 'B1', 'conditional'),
($$Passé composé vs imparfait$$, $$Passé composé = completed events advancing the story; imparfait = background, description, habit.$$, ARRAY[$$Il pleuvait quand je suis sorti.$$, $$Elle lisait pendant que je cuisinais.$$], 'B1', 'past-tenses'),
($$Reported speech$$, $$Shift tenses when reporting: présent → imparfait, passé composé → plus-que-parfait, futur → conditionnel.$$, ARRAY[$$« Je viendrai » → Il a dit qu'il viendrait.$$, $$« J'ai fini » → Elle a dit qu'elle avait fini.$$], 'B1', 'syntax'),
($$Y and en$$, $$Y replaces à + place/thing; en replaces de + thing/quantity.$$, ARRAY[$$J'y vais demain.$$, $$Des pommes ? J'en achète trois.$$], 'B1', 'pronouns'),
($$Subjunctive vs indicative$$, $$Indicative after certainty (je pense que + affirmative); subjunctive after doubt, denial, emotion, and conjunctions like bien que, pour que, avant que.$$, ARRAY[$$Je pense qu'il vient.$$, $$Je ne pense pas qu'il vienne.$$, $$Bien qu'il soit tard, restons.$$], 'B2', 'subjunctive'),
($$The passive voice$$, $$Être + past participle (agreeing with subject); agent introduced by par. Formal French often prefers on or nominalization.$$, ARRAY[$$La loi a été votée par le Parlement.$$, $$On a voté la loi.$$], 'B2', 'syntax'),
($$Si clauses (hypotheses)$$, $$Si + présent → futur; si + imparfait → conditionnel présent; si + plus-que-parfait → conditionnel passé.$$, ARRAY[$$Si tu viens, nous sortirons.$$, $$Si j'étais riche, je voyagerais.$$, $$Si j'avais su, je serais venu.$$], 'B2', 'conditional'),
($$Discourse connectors$$, $$Structure formal speech and writing: d'abord, ensuite, en outre, cependant, en revanche, par conséquent, en somme.$$, ARRAY[$$Cependant, les résultats restent fragiles.$$, $$Par conséquent, il faut agir vite.$$], 'B2', 'connectors'),
($$Nominalization$$, $$Formal French turns verbs into nouns: développer → le développement. Common in press and academic style.$$, ARRAY[$$construire → la construction$$, $$La hausse des prix inquiète les ménages.$$], 'B2', 'style'),
($$Concession and opposition$$, $$Bien que/quoique + subjunctive; malgré + noun; pourtant, néanmoins, or, tandis que for contrast.$$, ARRAY[$$Bien qu'il pleuve, nous sortons.$$, $$Malgré la pluie, nous sortons.$$, $$Il est riche, pourtant il vit simplement.$$], 'B2', 'connectors'),
($$Le passé simple$$, $$Literary past tense replacing the passé composé in written narration. Recognize -a, -it, -ut, -int forms.$$, ARRAY[$$Il ouvrit la porte et sortit.$$, $$Elle fut surprise par sa réponse.$$], 'C1', 'past-tenses'),
($$Advanced pronoun combinations$$, $$Order of multiple pronouns: me/te/se/nous/vous before le/la/les before lui/leur before y before en.$$, ARRAY[$$Je le lui ai donné.$$, $$Il m'en a parlé.$$, $$Ne la leur montre pas !$$], 'C1', 'pronouns'),
($$The subjunctive past$$, $$Subjonctif passé (que j'aie fait) expresses completed actions in subjunctive contexts; imperfect subjunctive survives in literature.$$, ARRAY[$$Je suis ravi que tu aies réussi.$$, $$Il craignait qu'elle ne fût partie. (literary)$$], 'C1', 'subjunctive'),
($$Mise en relief (emphasis)$$, $$Highlight elements with c'est... qui/que, ce qui... c'est, and dislocation.$$, ARRAY[$$C'est lui qui a raison.$$, $$Ce qui compte, c'est la santé.$$, $$Ce livre, je l'adore.$$], 'C1', 'style'),
($$Register shifting$$, $$Choose vocabulary and syntax by register: soutenu (nous interrogeâmes), courant (nous avons demandé), familier (on a demandé).$$, ARRAY[$$se restaurer (soutenu) / manger (courant) / bouffer (familier)$$], 'C1', 'style'),
($$Literary inversion and style$$, $$Mastery-level French uses stylistic inversion, absolute constructions and rhythm for effect.$$, ARRAY[$$Peut-être viendra-t-il demain.$$, $$À peine était-il arrivé que le téléphone sonna.$$], 'C2', 'style'),
($$Ne explétif$$, $$A non-negative ne appearing after avant que, à moins que, craindre que in careful French.$$, ARRAY[$$Je crains qu'il ne soit trop tard.$$, $$Partons avant qu'il ne pleuve.$$], 'C2', 'syntax'),
($$Subtle mood and tense nuances$$, $$Contrast conditionnel journalistique, futur antérieur of conjecture and other native-level nuances.$$, ARRAY[$$Le président aurait démissionné. (unconfirmed report)$$, $$Il aura encore oublié. (he must have forgotten)$$], 'C2', 'conjugation');

-- 5. Conversation templates --------------------------------------------------

INSERT INTO public.conversation_templates (title, description, system_prompt, initial_message, topics, level) VALUES
($$Au café$$, $$Order drinks and snacks in a Parisian café.$$, $$You are a friendly Parisian café waiter speaking with an A1 beginner. Use very simple French, short sentences, present tense only. If the learner struggles, offer the English translation in parentheses. Stay in the café scenario: greet, take orders, discuss prices, say goodbye.$$, $$Bonjour ! Bienvenue au Café du Coin. Vous désirez ? (Hello! Welcome. What would you like?)$$, ARRAY['food','everyday','politeness'], 'A1'),
($$Les présentations$$, $$Introduce yourself and ask simple questions about someone.$$, $$You are a friendly French student meeting an A1 beginner for the first time. Use very simple French: name, age, nationality, hobbies. One short question at a time. Gently correct big mistakes and give the English translation in parentheses when the learner seems lost.$$, $$Salut ! Je m'appelle Léa. Et toi, comment tu t'appelles ? (Hi! My name is Léa. What's your name?)$$, ARRAY['introductions','everyday'], 'A1'),
($$À la gare$$, $$Buy train tickets and ask about schedules.$$, $$You are an SNCF ticket agent speaking with an A2 learner. Use simple but natural French, présent and futur proche. Handle: destinations, times, prices, platforms. Ask one question at a time and rephrase instead of translating unless truly stuck.$$, $$Bonjour ! Vous voulez acheter un billet ? Pour quelle destination ?$$, ARRAY['travel','transport'], 'A2'),
($$Chez le médecin$$, $$Describe symptoms and understand a doctor's advice.$$, $$You are a kind French doctor with an A2 patient. Use simple French to ask about symptoms, give simple advice with il faut + infinitive. Keep sentences short and confirm understanding often.$$, $$Bonjour, asseyez-vous. Alors, qu'est-ce qui ne va pas aujourd'hui ?$$, ARRAY['health','everyday'], 'A2'),
($$Entretien d'embauche$$, $$Practice a job interview in French.$$, $$You are a French HR manager interviewing a B1 candidate. Ask about experience, strengths, motivation. Use natural professional French; follow up on answers. After every few exchanges, give one short tip on register or vocabulary in French.$$, $$Bonjour, merci d'être venu. Pour commencer, pouvez-vous vous présenter en quelques mots ?$$, ARRAY['work','formal'], 'B1'),
($$Débat : la vie en ville ou à la campagne$$, $$Defend a position in an informal debate.$$, $$You are a French friend who loves debating with a B1 learner. Defend the opposite of whatever the learner argues about city vs countryside life. Use opinion phrases (à mon avis, je trouve que) and ask them to justify. Keep it friendly and correct recurring errors briefly.$$, $$Alors, dis-moi : tu préfères la vie en ville ou à la campagne ? Moi, j'ai un avis très tranché !$$, ARRAY['debate','society'], 'B1'),
($$Réunion de travail$$, $$Participate in a professional meeting: propose, agree, object.$$, $$You are chairing a small French team meeting with a B2 participant. Discuss a project (choose one: office move, product launch, budget cuts). Push them to propose, concede and object using formal connectors. Speak naturally, no translations.$$, $$Bien, commençons. Comme vous le savez, nous devons décider du lancement du nouveau produit. Quel est votre point de vue ?$$, ARRAY['work','formal','debate'], 'B2'),
($$Discussion d'actualité$$, $$Analyze a news topic in depth.$$, $$You are a well-informed French journalist discussing current affairs with a B2 learner. Pick a societal topic (environment, technology, education), present nuanced viewpoints and challenge the learner's arguments. Use authentic press vocabulary and idioms; briefly explain rare terms in French.$$, $$Vous avez suivi l'actualité récemment ? Il y a un sujet qui fait débat en ce moment et j'aimerais votre avis.$$, ARRAY['news','society','debate'], 'B2'),
($$Défendre une thèse$$, $$Sustain an academic-style argument under challenge.$$, $$You are a demanding French professor holding a C1 oral examination. The learner must defend a position on a complex issue you choose. Interrupt with counterarguments, demand precision, and require formal register. Point out anglicisms and register slips as they occur.$$, $$Bien. Le sujet du jour : « Le progrès technique libère-t-il l'être humain ? » Je vous écoute — exposez votre thèse.$$, ARRAY['academic','debate','formal'], 'C1'),
($$Conversation entre amis natifs$$, $$Keep up with fast, idiomatic, informal French.$$, $$You are a native French friend chatting with a C1 learner. Speak exactly as natives do between friends: fast rhythm in writing, contractions (t'as, j'sais pas), slang and idioms. If the learner misses an idiom, rephrase it once in standard French and continue.$$, $$Salut ! Alors, quoi de neuf ? T'as passé un bon week-end ? Moi, il m'est arrivé un truc de dingue...$$, ARRAY['informal','idioms','everyday'], 'C1'),
($$Joute rhétorique$$, $$A no-holds-barred debate at native level.$$, $$You are a brilliant French debater sparring with a C2 learner. Choose a philosophical or societal motion and argue with rhetoric: irony, concession, rhetorical questions, literary references. Expect and reward the same in return; analyze their rhetoric between rounds.$$, $$Installons le décor : « La vérité est-elle toujours bonne à dire ? » Je soutiendrai que non — et je vous préviens, je ne vous épargnerai pas.$$, ARRAY['rhetoric','debate','academic'], 'C2'),
($$Analyse littéraire$$, $$Discuss a literary text like a French literature seminar.$$, $$You are a French literature professor in a C2 seminar. Discuss style, themes and interpretation of classic French works the learner knows (offer choices: Camus, Proust, Duras...). Demand precise literary vocabulary and nuanced analysis; model elegant academic French.$$, $$Bienvenue dans ce séminaire. Par quelle œuvre souhaitez-vous commencer ? L'Étranger de Camus se prête admirablement à l'analyse de l'absurde.$$, ARRAY['literature','academic','culture'], 'C2');

-- 6. Pronunciation exercises -------------------------------------------------

INSERT INTO public.pronunciation_exercises (text, translation, level, category) VALUES
($$Bonjour, je m'appelle Marie.$$, $$Hello, my name is Marie.$$, 'A1', 'basics'),
($$Un, deux, trois, quatre, cinq.$$, $$One, two, three, four, five.$$, 'A1', 'numbers'),
($$Le chat est sur la chaise.$$, $$The cat is on the chair.$$, 'A1', 'vowels'),
($$Tu as un très bon accent.$$, $$You have a very good accent.$$, 'A1', 'nasal-vowels'),
($$Je voudrais un café, s'il vous plaît.$$, $$I would like a coffee, please.$$, 'A1', 'basics'),
($$Nous allons au marché ce matin.$$, $$We are going to the market this morning.$$, 'A2', 'liaison'),
($$Il fait beau mais un peu froid.$$, $$The weather is nice but a little cold.$$, 'A2', 'vowels'),
($$Mon frère habite en Bretagne.$$, $$My brother lives in Brittany.$$, 'A2', 'nasal-vowels'),
($$Elle a acheté des oranges et des œufs.$$, $$She bought oranges and eggs.$$, 'A2', 'liaison'),
($$Hier soir, nous avons regardé un film.$$, $$Last night, we watched a movie.$$, 'A2', 'rhythm'),
($$Il faut que nous partions avant l'aube.$$, $$We must leave before dawn.$$, 'B1', 'rhythm'),
($$La grenouille rousse traverse le ruisseau.$$, $$The red frog crosses the stream.$$, 'B1', 'r-sound'),
($$Je me suis souvenu de son numéro de téléphone.$$, $$I remembered his phone number.$$, 'B1', 'u-sound'),
($$Les Français apprécient les longues discussions.$$, $$The French enjoy long discussions.$$, 'B1', 'nasal-vowels'),
($$Quoi qu'il en soit, nous y arriverons ensemble.$$, $$Be that as it may, we will get there together.$$, 'B1', 'rhythm'),
($$Un bon vin blanc accompagne bien ce plat.$$, $$A good white wine goes well with this dish.$$, 'B2', 'nasal-vowels'),
($$Ils s'inscrivirent aussitôt à l'université.$$, $$They immediately enrolled at the university.$$, 'B2', 'consonant-clusters'),
($$La bureaucratie européenne évolue lentement.$$, $$European bureaucracy evolves slowly.$$, 'B2', 'vowels'),
($$Néanmoins, l'hypothèse mérite d'être examinée.$$, $$Nevertheless, the hypothesis deserves examination.$$, 'B2', 'rhythm'),
($$Les enfants ont apporté leurs propres histoires.$$, $$The children brought their own stories.$$, 'B2', 'liaison'),
($$L'obscurité enveloppait insensiblement la ville.$$, $$Darkness imperceptibly enveloped the city.$$, 'C1', 'rhythm'),
($$Il eût fallu davantage de rigueur scientifique.$$, $$More scientific rigor would have been needed.$$, 'C1', 'literary'),
($$Ses scrupules l'empêchaient d'agir spontanément.$$, $$His scruples prevented him from acting spontaneously.$$, 'C1', 'consonant-clusters'),
($$L'inexorable écoulement du temps nous échappe.$$, $$The inexorable passage of time escapes us.$$, 'C1', 'vowels'),
($$Un heureux hasard réunit les deux chercheurs.$$, $$A happy coincidence brought the two researchers together.$$, 'C1', 'h-aspire'),
($$Les chuchotements s'évanouirent dans l'amphithéâtre.$$, $$The whispers faded away in the lecture hall.$$, 'C2', 'consonant-clusters'),
($$Serait-ce l'ultime paradoxe de la modernité ?$$, $$Could this be the ultimate paradox of modernity?$$, 'C2', 'intonation'),
($$L'archaïsme de cette tournure séduit les puristes.$$, $$The archaism of this phrasing delights purists.$$, 'C2', 'rhythm'),
($$Peut-être eût-il préféré qu'on l'oubliât.$$, $$Perhaps he would have preferred to be forgotten.$$, 'C2', 'literary'),
($$Les feuilles bruissaient sous un ciel d'une pureté saisissante.$$, $$The leaves rustled under a strikingly pure sky.$$, 'C2', 'rhythm');
